class TestPrimaryHolderTransactions:
    """Primary holder must be able to perform all transaction types."""

    def test_primary_can_deposit(self, funded_account, primary_holder):
        new_balance = funded_account.deposit(primary_holder, Decimal("500.00"))
        assert new_balance == Decimal("5500.00")

    def test_primary_deposit_recorded_in_log(self, funded_account, primary_holder):
        funded_account.deposit(primary_holder, Decimal("100.00"))
        assert funded_account.transaction_log[-1]["type"] == TransactionType.DEPOSIT
        assert funded_account.transaction_log[-1]["actor"] == primary_holder.holder_id

    def test_primary_can_withdraw(self, funded_account, primary_holder):
        new_balance = funded_account.withdraw(primary_holder, Decimal("1000.00"))
        assert new_balance == Decimal("4000.00")

    def test_primary_withdrawal_recorded_in_log(self, funded_account, primary_holder):
        funded_account.withdraw(primary_holder, Decimal("200.00"))
        assert funded_account.transaction_log[-1]["type"] == TransactionType.WITHDRAWAL

    def test_primary_can_transfer(self, funded_account, primary_holder, target_account):
        new_balance = funded_account.transfer(primary_holder, Decimal("1500.00"), target_account)
        assert new_balance == Decimal("3500.00")
        assert target_account.balance == Decimal("1500.00")

    def test_primary_transfer_recorded_in_log(self, funded_account, primary_holder, target_account):
        funded_account.transfer(primary_holder, Decimal("500.00"), target_account)
        assert funded_account.transaction_log[-1]["type"] == TransactionType.TRANSFER

    def test_primary_multiple_transactions_accumulate_correctly(self, funded_account, primary_holder):
        funded_account.deposit(primary_holder, Decimal("1000.00"))   # 6000
        funded_account.withdraw(primary_holder, Decimal("500.00"))   # 5500
        funded_account.withdraw(primary_holder, Decimal("2500.00"))  # 3000
        assert funded_account.balance == Decimal("3000.00")
        assert len(funded_account.transaction_log) == 3


