# TEST CLASS 3 – Secondary holder MUST NOT modify ownership
# ===========================================================================

class TestSecondaryHolderOwnershipRestrictions:
    """
    The secondary holder must never be able to alter account ownership,
    regardless of the specific operation requested.
    """

    def test_secondary_cannot_add_holder(
        self, funded_account, secondary_holder, another_holder
    ):
        with pytest.raises(OwnershipModificationError):
            funded_account.add_holder(secondary_holder, another_holder)

    def test_secondary_cannot_remove_holder(
        self, funded_account, secondary_holder, primary_holder
    ):
        with pytest.raises(OwnershipModificationError):
            funded_account.remove_holder(secondary_holder, primary_holder)

    def test_secondary_cannot_promote_themselves_to_primary(
        self, funded_account, secondary_holder
    ):
        with pytest.raises(OwnershipModificationError):
            funded_account.change_primary(secondary_holder, secondary_holder)

    def test_secondary_cannot_change_primary_to_third_party(
        self, funded_account, secondary_holder, another_holder
    ):
        with pytest.raises(OwnershipModificationError):
            funded_account.change_primary(secondary_holder, another_holder)

    def test_ownership_unchanged_after_secondary_attempt(
        self, funded_account, secondary_holder, another_holder, primary_holder
    ):
        """Account state must not mutate even if the call is rejected."""
        with pytest.raises(OwnershipModificationError):
            funded_account.add_holder(secondary_holder, another_holder)
        # Primary is still primary; another_holder is not a member
        assert funded_account.get_role(primary_holder) == AccountRole.PRIMARY
        assert funded_account.get_role(another_holder) is None

    def test_secondary_role_is_unchanged_after_rejection(
        self, funded_account, secondary_holder
    ):
        with pytest.raises(OwnershipModificationError):
            funded_account.change_primary(secondary_holder, secondary_holder)
        assert funded_account.get_role(secondary_holder) == AccountRole.SECONDARY

    def test_primary_can_add_holder(
        self, funded_account, primary_holder, another_holder
    ):
        """Positive control: primary CAN add a holder."""
        funded_account.add_holder(primary_holder, another_holder)
        assert funded_account.get_role(another_holder) == AccountRole.SECONDARY

    def test_primary_can_remove_secondary_holder(
        self, funded_account, primary_holder, secondary_holder
    ):
        """Positive control: primary CAN remove the secondary holder."""
        funded_account.remove_holder(primary_holder, secondary_holder)
        assert funded_account.get_role(secondary_holder) is None

    def test_primary_can_change_primary_to_secondary(
        self, funded_account, primary_holder, secondary_holder
    ):
        """Positive control: primary CAN transfer primary role."""
        funded_account.change_primary(primary_holder, secondary_holder)
        assert funded_account.get_role(secondary_holder) == AccountRole.PRIMARY
        assert funded_account.get_role(primary_holder) == AccountRole.SECONDARY


