class TestInsufficientFunds:

    def test_primary_withdraw_more_than_balance_raises(self, funded_account, primary_holder):
        with pytest.raises(InsufficientFundsError):
            funded_account.withdraw(primary_holder, Decimal("9999.00"))

    def test_secondary_withdraw_more_than_balance_raises(self, funded_account, secondary_holder):
        with pytest.raises(InsufficientFundsError):
            funded_account.withdraw(secondary_holder, Decimal("9999.00"))

    def test_primary_transfer_more_than_balance_raises(
        self, funded_account, primary_holder, target_account
    ):
        with pytest.raises(InsufficientFundsError):
            funded_account.transfer(primary_holder, Decimal("9999.00"), target_account)

    def test_secondary_transfer_more_than_balance_raises(
        self, funded_account, secondary_holder, target_account
    ):
        with pytest.raises(InsufficientFundsError):
            funded_account.transfer(secondary_holder, Decimal("9999.00"), target_account)

    def test_balance_unchanged_after_failed_withdrawal(self, funded_account, primary_holder):
        original = funded_account.balance
        with pytest.raises(InsufficientFundsError):
            funded_account.withdraw(primary_holder, Decimal("99999.00"))
        assert funded_account.balance == original

    def test_target_balance_unchanged_after_failed_transfer(
        self, funded_account, primary_holder, target_account
    ):
        with pytest.raises(InsufficientFundsError):
            funded_account.transfer(primary_holder, Decimal("99999.00"), target_account)
        assert target_account.balance == Decimal("0.00")

    def test_withdraw_exactly_zero_balance_raises(self, empty_account, primary_holder):
        with pytest.raises(InsufficientFundsError):
            empty_account.withdraw(primary_holder, Decimal("0.01"))

    def test_withdraw_entire_balance_succeeds(self, funded_account, primary_holder):
        """Edge case: withdrawing the exact available balance must succeed."""
        new_balance = funded_account.withdraw(primary_holder, Decimal("5000.00"))
        assert new_balance == Decimal("0.00")

    def test_sequential_withdrawals_that_exceed_balance_raise(
        self, funded_account, primary_holder, secondary_holder
    ):
        funded_account.withdraw(primary_holder, Decimal("3000.00"))  # balance → 2000
        with pytest.raises(InsufficientFundsError):
            funded_account.withdraw(secondary_holder, Decimal("2500.00"))  # would go negative


