            funded_account.withdraw(third_party, Decimal("100.00"))

    def test_third_party_cannot_transfer(self, funded_account, third_party, target_account):
        with pytest.raises(UnauthorisedError):
            funded_account.transfer(third_party, Decimal("100.00"), target_account)

    def test_third_party_cannot_add_holder(
        self, funded_account, third_party, another_holder
    ):
        with pytest.raises(UnauthorisedError):
            funded_account.add_holder(third_party, another_holder)

    def test_third_party_cannot_remove_holder(
        self, funded_account, third_party, secondary_holder
    ):
        with pytest.raises(UnauthorisedError):
            funded_account.remove_holder(third_party, secondary_holder)

    def test_balance_unchanged_after_unauthorised_deposit(
        self, funded_account, third_party
    ):
        original = funded_account.balance
        with pytest.raises(UnauthorisedError):
            funded_account.deposit(third_party, Decimal("500.00"))
        assert funded_account.balance == original

    def test_balance_unchanged_after_unauthorised_withdrawal(
        self, funded_account, third_party
    ):
        original = funded_account.balance
        with pytest.raises(UnauthorisedError):
            funded_account.withdraw(third_party, Decimal("500.00"))
        assert funded_account.balance == original

    def test_no_log_entry_created_for_unauthorised_action(
        self, funded_account, third_party
    ):
        with pytest.raises(UnauthorisedError):
            funded_account.deposit(third_party, Decimal("500.00"))
        assert len(funded_account.transaction_log) == 0

    def test_primary_cannot_be_removed_by_anyone(
        self, funded_account, primary_holder, secondary_holder
    ):
        """Removing the primary holder is a business-rule violation."""
        with pytest.raises(UnauthorisedError):
            funded_account.remove_holder(primary_holder, primary_holder)

