    def test_primary_transfer_over_limit_raises(
        self, funded_account, primary_holder, target_account
    ):
        with pytest.raises(LimitExceededError):
            funded_account.transfer(primary_holder, Decimal("3000.01"), target_account)

    def test_secondary_transfer_over_limit_raises(
        self, funded_account, secondary_holder, target_account
    ):
        with pytest.raises(LimitExceededError):
            funded_account.transfer(secondary_holder, Decimal("3000.01"), target_account)

    def test_balance_unchanged_after_limit_exceeded_withdrawal(
        self, funded_account, primary_holder
    ):
        original = funded_account.balance
        with pytest.raises(LimitExceededError):
            funded_account.withdraw(primary_holder, Decimal("5000.00"))
        assert funded_account.balance == original

    def test_target_balance_unchanged_after_limit_exceeded_transfer(
        self, funded_account, primary_holder, target_account
    ):
        with pytest.raises(LimitExceededError):
            funded_account.transfer(primary_holder, Decimal("5000.00"), target_account)
        assert target_account.balance == Decimal("0.00")

    def test_withdrawal_exactly_at_limit_succeeds(self, funded_account, primary_holder):
        """Boundary: exactly at the limit must be allowed."""
        new_balance = funded_account.withdraw(primary_holder, Decimal("3000.00"))
        assert new_balance == Decimal("2000.00")

    def test_no_log_entry_created_when_limit_exceeded(
        self, funded_account, primary_holder
    ):
        with pytest.raises(LimitExceededError):
            funded_account.withdraw(primary_holder, Decimal("5000.00"))
        assert len(funded_account.transaction_log) == 0

    def test_limit_applies_per_transaction_not_cumulative(
        self, funded_account, primary_holder
    ):
        """Two transactions each at the limit must both succeed individually."""
        funded_account.withdraw(primary_holder, Decimal("3000.00"))  # balance → 2000
        funded_account.deposit(primary_holder, Decimal("3000.00"))   # balance → 5000
        funded_account.withdraw(primary_holder, Decimal("3000.00"))  # balance → 2000
        assert funded_account.balance == Decimal("2000.00")

    @pytest.mark.parametrize("amount", [
        Decimal("3000.01"),
        Decimal("5000.00"),
        Decimal("9999.99"),
        Decimal("1000000.00"),
    ])
    def test_various_amounts_over_limit_raise(
        self, funded_account, primary_holder, target_account, amount
    ):
        # Ensure balance is high enough to isolate limit from funds check
        funded_account.deposit(primary_holder, Decimal("2000000.00"))
        with pytest.raises(LimitExceededError):
            funded_account.withdraw(primary_holder, amount)


